import { existsSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { ComponentLoader } from 'adminjs';
const currentDir = dirname(fileURLToPath(import.meta.url));
const componentLoader = new ComponentLoader();
const resolveComponentPath = (fileName) => {
    const localPath = join(currentDir, fileName);
    const sourcePath = join(currentDir, '..', '..', 'src', 'admin', fileName);
    return existsSync(localPath) ? localPath : sourcePath;
};
export const dashboardComponentId = componentLoader.add('OperationsDashboard', resolveComponentPath('dashboard.jsx'));
export const contentStudioComponentId = componentLoader.add('ContentStudioPage', resolveComponentPath('content-studio.jsx'));
export const jobCommandComponentId = componentLoader.add('JobCommandPage', resolveComponentPath('job-command.jsx'));
export const revenueOpsComponentId = componentLoader.add('RevenueOpsPage', resolveComponentPath('revenue-ops.jsx'));
componentLoader.override('SidebarBranding', resolveComponentPath('sidebar-branding.jsx'));
componentLoader.override('SidebarFooter', resolveComponentPath('sidebar-footer.jsx'));
componentLoader.override('SidebarPages', resolveComponentPath('sidebar-pages.jsx'));
componentLoader.override('SidebarResourceSection', resolveComponentPath('sidebar-resource-section.jsx'));
componentLoader.override('Sidebar', resolveComponentPath('sidebar.jsx'));
componentLoader.override('TopBar', resolveComponentPath('top-bar.jsx'));
componentLoader.override('Login', resolveComponentPath('login.jsx'));
export { componentLoader };
